{"script":"// Fetch current information about Shanghai
const fetch = async (url) => {
  const response = await fetch(url);
  return response;
};

// We can't use fetch directly without https module, let me use a different approach
const https = require('https');

function getJSON(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch(e) {
          resolve(data);
        }
      });
    }).on('error', reject);
  });
}

async function main() {
  try {
    // Get Shanghai weather
    const weather = await getJSON('https://wttr.in/Shanghai?format=j1');
    const current = weather.current_condition[0];
    console.log('=== Shanghai Current Weather ===');
    console.log(`Temperature: ${current.temp_C}°C`);
    console.log(`Feels like: ${current.FeelsLikeC}°C`);
    console.log(`Condition: ${current.weatherDesc[0].value}`);
    console.log(`Humidity: ${current.humidity}%`);
    console.log(`Wind: ${current.winddir16Point} ${current.windspeedKmph} km/h`);
    console.log(`Pressure: ${current.pressure} hPa`);

    // Get a short description from Wikipedia
    const wiki = await getJSON('https://en.wikipedia.org/api/rest_v1/page/summary/Shanghai');
    console.log('\n=== About Shanghai ===');
    console.log(wiki.extract);
  } catch(e) {
    console.error('Error:', e.message);
    // Fallback: just provide a summary
    console.log('Could not fetch real-time data.');
  }
}

main();
